// // This module performs a division operation on two 2-bit numbers. It calculates the quotient and remainder of the division. The inputs are 2-bit binary numbers, and the divisor should not be zero. If the divisor is zero, the quotient and remainder should both be set to zero. The output is valid only when a valid signal is high.
module divider_2bit (
    input [1:0] dividend,
    input [1:0] divisor,
    input valid,
    output reg [1:0] quotient,
    output reg [1:0] remainder
);
    always @(*) begin
        if (valid) begin
            if (divisor == 2'b00) begin
                quotient = 2'b00;
                remainder = 2'b00;
            end else begin
                quotient = dividend / divisor;
                remainder = dividend % divisor;
            end
        end else begin
            quotient = 2'b00;
            remainder = 2'b00;
        end
    end
endmodule
